import { createContext, useContext, useEffect, useMemo, useState } from 'react';

// Khởi tạo Context
export const CartContext = createContext(null);

export const CartProvider = ({ children }) => {
  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(true);

  // Khởi tạo giỏ hàng ban đầu từ localStorage
  useEffect(() => {
    try {
      const savedCart = localStorage.getItem('cart');
      if (savedCart) setCart(JSON.parse(savedCart));
    } catch (error) {
      console.error('Lỗi đọc giỏ hàng từ localStorage:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  // Hàm cập nhật trạng thái giỏ hàng
  const saveCartState = (newCart) => {
    setCart(newCart);
    localStorage.setItem('cart', JSON.stringify(newCart));
    window.dispatchEvent(new Event('storage'));
  };

  // Hàm thêm sản phẩm nhận kèm số lượng tùy chọn từ trang ProductDetail
  const addToCart = (product, customQuantity = 1) => {
    if (!product || !product.id) return;
    
    const qtyToAdd = Number(customQuantity) || 1;
    const existingProduct = cart.find((item) => item.id === product.id);
    let updatedCart;

    if (existingProduct) {
      updatedCart = cart.map((item) =>
        item.id === product.id
          ? { ...item, quantity: item.quantity + qtyToAdd }
          : item
      );
    } else {
      updatedCart = [...cart, { ...product, quantity: qtyToAdd }];
    }

    saveCartState(updatedCart);
  };

  const removeFromCart = (id) => {
    saveCartState(cart.filter((item) => item.id !== id));
  };

  const updateQuantity = (id, quantity) => {
    if (quantity <= 0) {
      removeFromCart(id);
      return;
    }
    saveCartState(cart.map((item) => item.id === id ? { ...item, quantity: Number(quantity) } : item));
  };

  const increaseQuantity = (id) => {
    saveCartState(cart.map((item) => item.id === id ? { ...item, quantity: item.quantity + 1 } : item));
  };

  const decreaseQuantity = (id) => {
    saveCartState(
      cart.map((item) => item.id === id ? { ...item, quantity: item.quantity - 1 } : item).filter((item) => item.quantity > 0)
    );
  };

  const clearCart = () => saveCartState([]);

  const cartTotal = useMemo(() => cart.reduce((t, i) => t + Number(i.price || 0) * i.quantity, 0), [cart]);
  const cartCount = useMemo(() => cart.reduce((t, i) => t + i.quantity, 0), [cart]);

  return (
    <CartContext.Provider value={{ cart, loading, addToCart, removeFromCart, updateQuantity, increaseQuantity, decreaseQuantity, clearCart, cartTotal, cartCount }}>
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => {
  const context = useContext(CartContext);
  if (!context) throw new Error('useCart phải ở trong CartProvider');
  return context;
};

// CỨU TINH Ở ĐÂY: Export default cả CartContext để các file cũ import không bị lỗi nữa!
export default CartContext;
